import requests

def test_bulk_export_unauthorized_client_returns_403():
    base_url = '<target_app_base_url>'
    payload = {
        'resourceType': 'Patient',
        'outputFormat': 'application/fhir+ndjson'
    }

    resp = requests.post(f'{base_url}/$export', json=payload)
    assert resp.status_code == 403, f'Expected 403, got {resp.status_code}'
    assert 'error' in resp.text.lower() or 'unauthorized' in resp.text.lower()

    headers_invalid = {'Authorization': 'Bearer invalid_token_xyz'}
    resp2 = requests.post(f'{base_url}/$export', json=payload, headers=headers_invalid)
    assert resp2.status_code == 403

import requests
from time import sleep

def test_bulk_export_empty_dataset_returns_valid_structure():
    base_url = '<target_app_base_url>'
    headers = {
        'Authorization': 'Bearer <valid_bulk_export_token>',
        'Content-Type': 'application/fhir+json'
    }
    payload = {
        'resourceType': 'Patient',
        'outputFormat': 'application/fhir+ndjson'
    }

    resp = requests.post(f'{base_url}/$export', json=payload, headers=headers)
    assert resp.status_code == 202
    content_location = resp.headers['Content-Location']

    for _ in range(30):
        poll_resp = requests.get(content_location, headers=headers)
        if poll_resp.status_code == 200:
            data = poll_resp.json()
            assert data.get('status') == 'completed'
            assert isinstance(data.get('output', []), list)
            assert len(data['output']) == 0
            break
        sleep(0.5)
    else:
        raise AssertionError('Job did not complete')
